#include <iostream>
#include <string>
using namespace std;

int main() {
    string date = "2024-03-15";

    cout << date.substr(0, 4) << endl;  // year
    cout << date.substr(5, 2) << endl;  // month
    cout << date.substr(8)    << endl;  // day

    string text = "I love Java programming";
    size_t pos = text.find("Java");
    if (pos != string::npos) {
        text.replace(pos, 4, "C++");
    }
    cout << text << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

int main() {
    string a = "hello";
    string b = "world";
    string c = "hello";

    cout << boolalpha;
    cout << (a == c) << endl;   // true — content comparison
    cout << (a == b) << endl;   // false
    cout << (a < b)  << endl;   // true — 'h' < 'w' lexicographically

    // Convert to uppercase:
    string upper = a;
    transform(upper.begin(), upper.end(), upper.begin(), ::toupper);
    cout << upper << endl;

    return 0;
}

