#include <iostream>
#include <string>
#include <sstream>
using namespace std;

int main() {
    // Build a string with stream:
    stringstream builder;
    builder << "Product: " << "Widget" << ", Price: $" << 29.99 << ", Stock: " << 42;
    cout << builder.str() << endl;

    // Parse space-separated values:
    string data = "Alice 25 87.5";
    stringstream parser(data);
    string name;
    int age;
    double score;
    parser >> name >> age >> score;
    cout << name << " aged " << age << " scored " << score << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <string_view>
using namespace std;

// Takes any string-like thing without copying:
bool startsWith(string_view str, string_view prefix) {
    return str.substr(0, prefix.size()) == prefix;
}

bool contains(string_view haystack, string_view needle) {
    return haystack.find(needle) != string_view::npos;
}

int main() {
    string s = "Hello, C++ World!";

    cout << boolalpha;
    cout << startsWith(s, "Hello") << endl;  // works with string
    cout << startsWith("Goodbye", "Good") << endl;  // works with literal
    cout << contains(s, "C++") << endl;
    cout << contains(s, "Java") << endl;

    return 0;
}
